import React from 'react';
import { STATUS_META } from '../data/mockData';
import { timeAgo } from '../utils/helpers';

export function Badge({ status }) {
  const meta = STATUS_META[status] || { label: status, color: '#000', bg: '#eee' };
  return (
    <span style={{ background: meta.bg, color: meta.color, padding: '2px 8px', borderRadius: 4, fontSize: 11, fontWeight: 700, textTransform: 'uppercase' }}>
      {meta.label}
    </span>
  );
}

export default function ComplaintCard({ complaint, onAccept, onAssign, onDetails }) {
  const isCritical = complaint.severity === 'critical';
  return (
    <div style={{ background: '#fff', borderRadius: 12, border: '1px solid #DDE3E9', overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
      <div style={{ height: 120, background: '#1565C0', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: '#fff', position: 'relative', padding: 12 }}>
        {isCritical && <span style={{ position: 'absolute', top: 8, left: 8, background: '#D32F2F', fontSize: 10, padding: '2px 6px', borderRadius: 4, fontWeight: 800 }}>⚠️ CRITICAL</span>}
        <div style={{ fontSize: 28 }}>{complaint.emoji || '🗑️'}</div>
        <div style={{ fontSize: 11, opacity: 0.8, marginTop: 4 }}>No Photo Uploaded</div>
      </div>
      
      <div style={{ padding: 14, flex: 1, display: 'flex', flexDirection: 'column', gap: 6 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontSize: 10, fontFamily: 'monospace', color: '#7A8FA6', fontWeight: 600 }}>{complaint.customTicketId}</span>
          <Badge status={complaint.status} />
        </div>
        
        <h4 style={{ margin: 0, fontSize: 14, fontWeight: 700, color: '#0D1117' }}>{complaint.area} — {complaint.gtype}</h4>
        <div style={{ fontSize: 11, color: '#546E7A' }}>📍 {complaint.station?.name}</div>
        <div style={{ fontSize: 11, color: '#7A8FA6', marginTop: 'auto' }}>🕒 {timeAgo(complaint.reportedAt)} • By {complaint.reportedBy}</div>
        
        <div style={{ display: 'flex', gap: 6, marginTop: 10 }}>
          {complaint.status === 'NEW' && onAccept && (
            <button onClick={() => onAccept(complaint.id)} style={{ flex: 1, background: '#1565C0', color: '#fff', border: 'none', padding: '6px', borderRadius: 6, fontWeight: 700, cursor: 'pointer', fontSize: 12 }}>Accept</button>
          )}
          {complaint.status === 'ACCEPTED' && onAssign && (
            <button onClick={() => onAssign(complaint)} style={{ flex: 1, background: '#4527A0', color: '#fff', border: 'none', padding: '6px', borderRadius: 6, fontWeight: 700, cursor: 'pointer', fontSize: 12 }}>Assign Cleaner</button>
          )}
          {onDetails && (
            <button onClick={() => onDetails(complaint)} style={{ background: '#F7F9FC', border: '1px solid #DDE3E9', padding: '6px 12px', borderRadius: 6, fontSize: 12, cursor: 'pointer' }}>Details</button>
          )}
        </div>
      </div>
    </div>
  );
}
